from googleapiclient import discovery
from oauth2client.service_account import ServiceAccountCredentials
import urllib, os


def getCloudStorage(event):
    return  event["resources"][0]["name"]

def callImageMagick(event):

    # get filename from cloud storage
    eventFileName = getCloudStorage(event)
    print(eventFileName)

    # Get ImageMagick script
    imageMagickScript = urllib.request.urlopen('https://www-us.apache.org/dist//imagemagick70/ImageMagick-7.0.8-6-Q16-HDRI-Windows64-dll.exe').read()
    filename = os.path.join(os.getenv('FUNCTION_ROOT'), 'tmp', 'ImageMagick.exe')
    f = open(filename,'wb')
    f.write(imageMagickScript)

    # Get image to convert
    bucketName, key = eventFileName.split("/")[-2:]
    
    print (bucketName, key)
    storage_service = discovery.build('storage', 'v1')
    media = discovery. build('storage').objects().get_media(bucket=bucketName, object=key)
    #print ("here")

    file = open('/tmp/imageMagick.jpg','wb') 
    file.write(media._resumable_body())

def convert_jpeg2png(event):
    imageMagickCommand = 'convert imageMagick.jpg imageMagick.png'
    os.system (imageMagickCommand)